mapper.select:
select id, user_id, dish_id, dish_name, dish_price, quantity, create_time, update_time
from shopping_cart
where user_id = #{userId}
  and dish_id = #{dishId}

mapper.update:
update shopping_cart
set quantity = #{quantity}
where id = #{id}

mapper.delete:
delete from shopping_cart
where user_id = #{userId}
  and dish_id = #{dishId}
